mapper.delete:
DELETE FROM file_download_history
WHERE version_id IN (
    SELECT version_id FROM file_versions WHERE file_id = #{fileId}
)

mapper.select:
SELECT file_id
FROM (
    SELECT file_id
    FROM files
    WHERE project_id = #{projectId}
      AND logical_name = #{logicalName}
      AND is_deleted = 'N'

      AND task_id = #{taskId}


      AND task_id IS NULL

    ORDER BY TO_NUMBER(file_id) DESC
)
WHERE ROWNUM = 1

mapper.insert:

    SELECT TO_CHAR(NVL(MAX(version_id), 0) + 1) FROM file_versions

INSERT INTO file_versions (
                            version_id
                          	, file_id
                          	, version_number
                          	, file_path
                          	, file_size
                          	, uploader
                          	, uploaded_at
                          	, saved_name
                          )
VALUES (
         #{versionId}
       	 , #{fileId}
       	 , #{versionNumber}
       	 , #{filePath}
       	 , #{fileSize}
         , #{uploader}
       	 , SYSDATE
       	 , #{savedName}
       )


    SELECT TO_CHAR(NVL(MAX(history_id), 0) + 1) FROM file_download_history

INSERT INTO file_download_history (
                                    history_id
                                  , version_id
                                  , downloader
                                  , downloaded_at
                                   )
VALUES (
         #{historyId}
       , #{versionId}
       , #{downloader}
       , SYSDATE
       )
